const MISCONCEPTIONS = [
  { slug: 'israel', title: 'Israel', summary: 'Myths about Israel\'s founding, "colonialism," and the conflict.' },
  { slug: 'talmud', title: 'The Talmud', summary: 'Misquotes and false claims about what the Talmud says.' },
  { slug: 'jewish-race', title: 'The Jewish Race', summary: 'Facts about Jewish identity: ethnicity, religion, and race.' },
  { slug: 'conspiracy', title: 'Conspiracy Theories', summary: 'Classic antisemitic conspiracy myths and why they\'re false.' },
]

// Topic body_text enriched with context that Hashem.Faith articles address
const MISCONCEPTION_TOPICS = [
  { topic_slug: 'israel', title: 'Israel', body_text: '<p><strong>"Israel is a colonial project."</strong> Jews have had a continuous presence in the land for millennia. Modern Zionism sought self-determination in the ancestral homeland after persecution in Europe and elsewhere. The state was established with international recognition (UN 1947–48). Calling it "colonial" erases Jewish indigeneity and history.</p><p><strong>"Israel has no right to exist."</strong> Israel is a sovereign state and a member of the UN. Denying only the Jewish state\'s right to exist, while accepting others, is a form of antisemitism (see IHRA definition).</p><p><strong>"Israel is committing genocide."</strong> As covered in Definitions, genocide requires intent to destroy a group. Israel is fighting Hamas; its aim is not to eliminate Palestinians as a people. Casualties of war are not by themselves genocide.</p><p>The name "Israel" and its biblical and historical meaning are explained in depth at Hashem.Faith.</p>', sort_order: 1 },
  { topic_slug: 'talmud', title: 'The Talmud', body_text: '<p><strong>"The Talmud says X about non-Jews."</strong> The Talmud is a vast legal and narrative corpus. Isolated lines are often taken out of context, mistranslated, or from passages that are debated or obsolete. Serious understanding requires scholarship and context.</p><p><strong>"The Talmud is secret or evil."</strong> The Talmud is studied openly and is the basis of Jewish law and tradition. Antisemites have long weaponized fake or distorted "quotes" to portray Jews as hostile to non-Jews.</p><p>Hashem.Faith addresses myths that the Talmud commands lying, dehumanizes gentiles, or is hostile to Christianity—with citations and context.</p>', sort_order: 2 },
  { topic_slug: 'jewish-race', title: 'The Jewish Race', body_text: '<p><strong>"Are Jews a race?"</strong> Jews are an ethnoreligious group. Identity is passed through family and community; there is genetic diversity but also shared ancestry among many Jews. Nazis racialized Jews to justify genocide; today, many Jews identify as both an ethnicity and a religion.</p><p><strong>"Jews are white / not white."</strong> Jewish identity predates modern racial categories. Jews have been classified differently in different times and places. Reducing Jews to a single "race" ignores this history and diversity.</p><p>Hashem.Faith discusses whether Judaism is a religion or race, where gentiles fit in the Jewish worldview, and refutes the myth that Jewish texts dehumanize non-Jews.</p>', sort_order: 3 },
  { topic_slug: 'conspiracy', title: 'Conspiracy Theories', body_text: '<p><strong>"Jews control the media / banks / government."</strong> Classic antisemitic conspiracy with no evidence. It has been used for centuries to blame Jews for societal problems and to justify violence.</p><p><strong>"The Holocaust didn\'t happen" or "was exaggerated."</strong> Holocaust denial is false and antisemitic. The evidence—documentation, testimony, sites—is overwhelming.</p><p><strong>"Israel did 9/11" or "Jews knew in advance."</strong> Baseless conspiracy theories that recycle antisemitic tropes about Jewish power and malice.</p><p>The claim that "the Jews killed Jesus" and conspiracy narratives about Jewish lobbying (e.g. AIPAC/FARA) are addressed with historical and legal context at Hashem.Faith.</p>', sort_order: 4 },
]

// Misconception entries: Israel myths (list+detail like Conspiracies)
const ISRAEL_MISCONCEPTION_ENTRIES = [
  { slug: 'israel-colonial-project', title: 'Israel Is a Colonial Project', summary: 'The claim that Israel was created by European colonialism and has no indigenous tie to the land.', body_text: '<h3>History</h3><p>The "colonial" framing of Israel emerged in Soviet and later anti-Zionist rhetoric to deny Jewish indigeneity. It treats Jewish return to the land as an alien European implant.</p><h3>Why</h3><p>Delegitimizing Israel as "colonial" supports the geopolitical and religious aim of actors who seek to eliminate the Jewish state. It erases millennia of Jewish presence and connection to the land.</p><h3>Facts</h3><p>Jews have had a continuous presence and tie to the land for thousands of years. Modern Zionism sought self-determination in the ancestral homeland after persecution and genocide in Europe. Israel was established with UN recognition (1947–48). Calling it "colonial" ignores Jewish history and the fact that Jews are indigenous to the region.</p>', sort_order: 1, sources: [{ label: 'What does Israel mean?', url: `${HASHEM}/what-does-israel-mean/` }] },
  { slug: 'original-israel', title: 'The Original Israel / Biblical Israel', summary: 'Myths that the ancient Israelites were not the ancestors of today\'s Jews, or that "Israel" was invented.', body_text: '<h3>History</h3><p>Antisemites and some anti-Zionist narratives claim that modern Jews have no connection to the biblical Israelites—e.g., the Khazar myth or the idea that "Israel" is a modern fabrication.</p><h3>Why</h3><p>Denying Jewish indigeneity is used to strip Israel of legitimacy and to portray Jews as foreign occupiers.</p><h3>Facts</h3><p>Archaeological, genetic, and textual evidence supports Jewish continuity from ancient Israel and Judah through the diaspora. The name Israel, the Hebrew language, and Jewish attachment to the land are well documented. The Khazar theory has been debunked by scholarship. See the site\'s Conspiracies section (Khazar myth) and Hashem.Faith on Jewish identity.</p>', sort_order: 2, sources: [] },
  { slug: 'uss-liberty', title: 'The USS Liberty Incident', summary: 'The claim that Israel deliberately attacked the U.S. ship USS Liberty in 1967 to drag America into war or hide war crimes.', body_text: '<h3>History</h3><p>On June 8, 1967, during the Six-Day War, Israeli forces struck the U.S. intelligence ship USS Liberty in international waters off the Sinai coast. Thirty-four American servicemen were killed. Conspiracy theories claim the attack was intentional—to pull the U.S. into the war, to hide Israeli actions, or to prevent the U.S. from learning something.</p><h3>Why</h3><p>The myth is used to portray Israel as a hostile actor that kills Americans and to undermine the U.S.–Israel alliance. It is promoted by some who seek to isolate Israel.</p><h3>Facts</h3><p>Multiple U.S. and Israeli investigations concluded the attack was a tragic case of mistaken identity during a chaotic war: Israeli forces misidentified the ship. Israel apologized and paid compensation. Senior U.S. officials (including the ship\'s commander and intelligence officers) and the CIA have rejected the deliberate-attack thesis. The incident was horrific; the conspiracy that it was intentional is not supported by the evidence.</p>', sort_order: 3, sources: [] },
  { slug: 'iraq-war-israel', title: 'Israel Made the U.S. Go to War in Iraq', summary: 'The claim that Israel or "Jewish neocons" pushed America into the 2003 Iraq War.', body_text: '<h3>History</h3><p>After the 2003 invasion of Iraq, a narrative spread that Israel or a "cabal" of Jewish neoconservatives had engineered the war for Israeli or Jewish interests.</p><h3>Why</h3><p>The myth recycles the trope of Jews pulling the strings of U.S. policy and deflects responsibility from the actual decision-makers. It is used to turn Americans against Israel and to fuel conspiracy thinking.</p><h3>Facts</h3><p>U.S. policy on Iraq was made by the elected president and his cabinet, with broad congressional and public debate. The decision was driven by many factors (WMD concerns, post-9/11 security policy, regime change). Attributing the war to "Israel" or "the Jews" is an antisemitic conspiracy that ignores the real chain of command and has been widely debunked.</p>', sort_order: 4, sources: [] },
  { slug: 'israel-did-9-11', title: 'Israel Did 9/11 or Knew In Advance', summary: 'The conspiracy that Israel or Jews orchestrated or had foreknowledge of the September 11 attacks.', body_text: '<h3>History</h3><p>Soon after 9/11, conspiracy theories claimed Israel or "the Jews" carried out the attacks or had foreknowledge. Variations include claims that Jews were warned to stay away from the World Trade Center.</p><h3>Why</h3><p>The conspiracy deflects blame from the actual perpetrators (al-Qaeda), recycles antisemitic tropes about Jewish power and malice, and is promoted by state actors seeking to divide Americans and undermine the U.S.–Israel alliance.</p><h3>Facts</h3><p>There is no evidence that Israel or Jews carried out or had advance knowledge of 9/11. The 9/11 Commission and intelligence investigations attribute the attacks to al-Qaeda. Claims of Israeli foreknowledge have been investigated and rejected. This is addressed in depth in the site\'s Conspiracies section.</p>', sort_order: 5, sources: [] },
  { slug: 'israel-controls-trump', title: 'Israel Controls Trump (or U.S. Presidents)', summary: 'The claim that Israel or "Zionists" control U.S. presidents or dictate U.S. policy.', body_text: '<h3>History</h3><p>Accusations that Israel or "the Jewish lobby" control U.S. leaders have circulated for decades. Under the Trump administration, some claimed Trump was "owned" by Israel or by Sheldon Adelson and other pro-Israel donors.</p><h3>Why</h3><p>The narrative suggests American support for Israel is not a legitimate policy choice but the result of secret or illegitimate control. It is pushed by foreign actors (Iran, Russia, etc.) to divide Americans and turn them against their ally Israel.</p><h3>Facts</h3><p>U.S. support for Israel is a matter of public policy, law, and alliance. Presidents make decisions for many reasons; there is no evidence that Israel "controls" any U.S. leader. The claim is an antisemitic conspiracy that echoes dual-loyalty and "Jewish power" tropes. See the site\'s Conspiracies section (Israel controls America, AIPAC).</p>', sort_order: 6, sources: [] },
  { slug: 'israel-apartheid', title: 'Israel Is an Apartheid State', summary: 'The charge that Israel practices apartheid against Palestinians.', body_text: '<h3>History</h3><p>The "apartheid" label has been applied to Israel by some advocacy groups and governments, equating Israeli policy with South African apartheid.</p><h3>Why</h3><p>Calling Israel "apartheid" is used to delegitimize and isolate the Jewish state and to justify boycotts or sanctions. It serves the goal of actors who seek to eliminate Israel.</p><h3>Facts</h3><p>Israeli law does not establish racial separation or second-class citizenship by race. Arab citizens of Israel have equal legal rights and participate in politics, the judiciary, and civil society. The situation in the West Bank and Gaza involves occupation and conflict with non-citizen populations—complex and contested, but not analogous to South African apartheid, which was a legal system of racial hierarchy. Many scholars and governments reject the apartheid characterization; the charge is often used as political rhetoric rather than legal analysis.</p>', sort_order: 7, sources: [] },
  { slug: 'israel-no-right-to-exist', title: 'Israel Has No Right to Exist', summary: 'The claim that the Jewish state is illegitimate and should not exist.', body_text: '<h3>History</h3><p>Denial of Israel\'s right to exist has been a feature of some anti-Zionist and antisemitic rhetoric since the state\'s founding.</p><h3>Why</h3><p>Denying only the Jewish state\'s right to exist, while accepting other states, is a form of antisemitism (IHRA definition). It supports the aim of those who seek to wipe Israel off the map.</p><h3>Facts</h3><p>Israel is a sovereign state, a member of the UN, with recognized borders and diplomatic relations. Jews have an ancient and continuous tie to the land. Denying Israel\'s right to exist is antisemitic and rejects the principle of self-determination for the Jewish people.</p>', sort_order: 8, sources: [] },
]

// Misconception entries: The Jewish Race (ethnicities, Khazar, etc.)
const JEWISH_RACE_MISCONCEPTION_ENTRIES = [
  { slug: 'ashkenazi', title: 'Ashkenazi Jews', summary: 'Who Ashkenazi Jews are and myths about their origins or "race."', body_text: '<h3>History</h3><p>Ashkenazi Jews are the Jewish communities that developed in Central and Eastern Europe (Germany, Poland, Russia, etc.). They have distinct liturgical and cultural traditions and today make up a large share of world Jewry.</p><h3>Why</h3><p>Antisemites sometimes single out Ashkenazi Jews for conspiracy theories (e.g., Khazar myth) to deny their Middle Eastern origins and delegitimize Israel.</p><h3>Facts</h3><p>Genetic and historical research shows Ashkenazi Jews have substantial Levantine and Middle Eastern ancestry. They are not "European" converts with no tie to the land of Israel. The Khazar theory—that Ashkenazi Jews descend mainly from Khazars—has been debunked. Ashkenazi is an ethnic/cultural designation within the Jewish people, not a separate "race."</p>', sort_order: 1, sources: [] },
  { slug: 'sephardi', title: 'Sephardi Jews', summary: 'Who Sephardi Jews are and their place in the Jewish people.', body_text: '<h3>History</h3><p>Sephardi Jews are those whose traditions derive from the Jewish communities of the Iberian Peninsula (Spain and Portugal) before the expulsions of the late 15th century. They spread across the Mediterranean, the Balkans, and beyond.</p><h3>Why</h3><p>Understanding Jewish diversity helps counter the myth that "Jews" are a single monolithic or "racial" bloc. Sephardi history also refutes the idea that Jews are only "European" or only "Middle Eastern."</p><h3>Facts</h3><p>Sephardi Jews have distinct liturgy, pronunciation of Hebrew, and customs. They are part of the same Jewish people as Ashkenazi, Mizrahi, and other communities. Jewish identity is ethnoreligious and encompasses multiple diaspora traditions.</p>', sort_order: 2, sources: [] },
  { slug: 'mizrahi', title: 'Mizrahi Jews', summary: 'Who Mizrahi Jews are and myths about "Jewish race" or Middle Eastern Jews.', body_text: '<h3>History</h3><p>Mizrahi Jews are those from the Middle East, North Africa, and the Caucasus—communities that never left the broader region and often spoke Arabic, Judeo-Arabic, or other languages.</p><h3>Why</h3><p>Antisemites sometimes portray "Jews" as exclusively white or European to fuel "colonial" narratives about Israel. Mizrahi Jewry shows that Jews have always been diverse and that many never left the Middle East.</p><h3>Facts</h3><p>Mizrahi Jews are an integral part of the Jewish people with ancient roots in the region. Many fled or were expelled from Arab and Muslim countries after 1948. They and their descendants make up a large share of Israel\'s Jewish population. The idea that "Jews" are one "race" or only European is false.</p>', sort_order: 3, sources: [] },
  { slug: 'beta-israel', title: 'Beta Israel (Ethiopian Jews)', summary: 'Who Beta Israel are and myths that they are not "real" Jews.', body_text: '<h3>History</h3><p>Beta Israel are the Jewish community of Ethiopia, with a long history and distinct traditions. They were recognized by Israeli rabbinic authorities and many made aliyah to Israel.</p><h3>Why</h3><p>Some have questioned whether Beta Israel are "really" Jewish, echoing historical patterns of excluding certain Jewish communities. Recognizing their place in the Jewish people counters racialized or narrow definitions of who counts as a Jew.</p><h3>Facts</h3><p>Beta Israel have maintained Jewish practice and identity for centuries. Israeli law and rabbinic recognition have affirmed their status. They are part of the global Jewish people. Denying their Jewishness is a form of exclusion that has no basis in fact.</p>', sort_order: 4, sources: [] },
  { slug: 'khazar-myth', title: 'The Khazar Myth (Jews Are Khazars)', summary: 'The false claim that Ashkenazi Jews descend from Khazars and are not "real" Jews.', body_text: '<h3>History</h3><p>The Khazar theory claims that Ashkenazi Jews descended mainly from the Khazars, a Turkic people whose rulers supposedly converted to Judaism in the medieval period. It was popularized to argue that modern Jews are "impostors" with no ancestral tie to the Land of Israel.</p><h3>Why</h3><p>Antisemites use the Khazar myth to deny Jewish indigeneity and to delegitimize Israel. It is promoted by those who seek to wipe Israel off the map and by foreign disinformation to divide the West.</p><h3>Facts</h3><p>Genetic and historical research has debunked the Khazar-origin thesis. Ashkenazi Jews show substantial Levantine and Middle Eastern ancestry. The Khazar kingdom did have a period of royal conversion, but there is no evidence that Ashkenazi Jewry descends mainly from Khazars. This is addressed in depth in the site\'s Conspiracies section (Khazar myth).</p>', sort_order: 5, sources: [] },
  { slug: 'jews-are-not-a-race', title: 'Are Jews a Race?', summary: 'Facts about Jewish identity: ethnicity, religion, and the misuse of "race."', body_text: '<h3>History</h3><p>Jews are an ethnoreligious group. Identity is passed through family and community. Nazis racialized Jews to justify genocide; today, "race" is a contested and often misused term when applied to Jews.</p><h3>Why</h3><p>Antisemites sometimes racialize Jews to exclude or target them, or to suggest that Jewish identity is "fake" or "invented." Understanding that Jews are a people with both religious and ethnic dimensions helps counter these distortions.</p><h3>Facts</h3><p>Jews have shared history, culture, and often ancestry, but there is genetic and cultural diversity (Ashkenazi, Sephardi, Mizrahi, Beta Israel, etc.). Many Jews identify as both an ethnicity and a religion. Reducing Jews to a single "race" ignores this diversity and history. Hashem.Faith discusses whether Judaism is a religion or race in depth.</p>', sort_order: 6, sources: [{ label: 'Is Judaism a religion or race?', url: `${HASHEM}/is-judaism-a-religion-or-race/` }] },
]

async function run() {
  const conn = await mysql.createConnection(config)
  console.log('Connected to MySQL.')

  await conn.execute('SET FOREIGN_KEY_CHECKS = 0')
  await conn.execute('TRUNCATE TABLE talmud_sources')
  await conn.execute('TRUNCATE TABLE conspiracy_sources')
  await conn.execute('TRUNCATE TABLE agitator_sources')
  await conn.execute('TRUNCATE TABLE misconception_entry_sources')
  await conn.execute('TRUNCATE TABLE misconception_entries')
  await conn.execute('TRUNCATE TABLE misconception_topics')
  await conn.execute('TRUNCATE TABLE talmud_entries')
  await conn.execute('TRUNCATE TABLE conspiracies')
  await conn.execute('TRUNCATE TABLE agitators')
  await conn.execute('TRUNCATE TABLE misconceptions')
  await conn.execute('TRUNCATE TABLE definitions')
  await conn.execute('TRUNCATE TABLE timeline_events')
  await conn.execute('SET FOREIGN_KEY_CHECKS = 1')
  console.log('Cleared existing data.')

  // Timeline events
  console.log('Inserting timeline_events...')
  for (const e of TIMELINE_EVENTS) {
    await conn.execute(
      'INSERT INTO timeline_events (year, label, region, description, source_label, source_url) VALUES (?, ?, ?, ?, ?, ?)',
      [e.year, e.label, e.region || null, e.description || null, e.source_label || null, e.source_url || null]
    )
  }
  console.log(`  ${TIMELINE_EVENTS.length} events.`)

  // Definitions (with Hashem.Faith further_reading)
  console.log('Inserting definitions...')
  for (const d of DEFINITIONS) {
    const furtherReading = DEFINITION_FURTHER_READING[d.slug] || []
    await conn.execute(
      'INSERT INTO definitions (slug, title, summary, body_text, further_reading) VALUES (?, ?, ?, ?, ?)',
      [d.slug, d.title, d.summary, d.body_text || null, furtherReading.length ? JSON.stringify(furtherReading) : null]
    )
  }
  console.log(`  ${DEFINITIONS.length} definitions.`)

  // Agitators + sources
  console.log('Inserting agitators and agitator_sources...')
  for (const a of AGITATORS) {
    const [r] = await conn.execute(
      'INSERT INTO agitators (slug, name, subtitle, description, image_url) VALUES (?, ?, ?, ?, ?)',
      [a.slug, a.name, a.subtitle, a.description, a.image_url || null]
    )
    const agitatorId = r.insertId
    let order = 0
    for (const s of a.sources) {
      await conn.execute(
        'INSERT INTO agitator_sources (agitator_id, date_label, text, url, sort_order) VALUES (?, ?, ?, ?, ?)',
        [agitatorId, s.date_label, s.text, s.url || null, order++]
      )
    }
  }
  console.log(`  ${AGITATORS.length} agitators with sources.`)

  // Conspiracies + sources
  console.log('Inserting conspiracies and conspiracy_sources...')
  for (const c of CONSPIRACIES) {
    const [r] = await conn.execute(
      'INSERT INTO conspiracies (slug, title, summary, body_text, category, tags, sort_order) VALUES (?, ?, ?, ?, ?, ?, ?)',
      [c.slug, c.title, c.summary || null, c.body_text || null, c.category || null, c.tags ? JSON.stringify(c.tags) : null, c.sort_order ?? 0]
    )
    const conspiracyId = r.insertId
    let order = 0
    for (const s of c.sources || []) {
      await conn.execute(
        'INSERT INTO conspiracy_sources (conspiracy_id, label, url, sort_order) VALUES (?, ?, ?, ?)',
        [conspiracyId, s.label, s.url || null, order++]
      )
    }
  }
  console.log(`  ${CONSPIRACIES.length} conspiracies with sources.`)

  // Talmud entries + sources (talmud.faithweb.com)
  console.log('Inserting talmud_entries and talmud_sources...')
  for (const t of TALMUD_ENTRIES) {
    const [r] = await conn.execute(
      'INSERT INTO talmud_entries (slug, title, summary, body_text, category, tags, sort_order) VALUES (?, ?, ?, ?, ?, ?, ?)',
      [t.slug, t.title, t.summary || null, t.body_text || null, t.category || null, t.tags ? JSON.stringify(t.tags) : null, t.sort_order ?? 0]
    )
    const entryId = r.insertId
    let order = 0
    for (const s of t.sources || []) {
      await conn.execute(
        'INSERT INTO talmud_sources (talmud_entry_id, label, url, sort_order) VALUES (?, ?, ?, ?)',
        [entryId, s.label, s.url || null, order++]
      )
    }
  }
  console.log(`  ${TALMUD_ENTRIES.length} talmud entries with sources.`)

  // Misconceptions + topics (one topic per misconception, matched by slug)
  console.log('Inserting misconceptions and misconception_topics...')
  const topicBySlug = Object.fromEntries(MISCONCEPTION_TOPICS.map((t) => [t.topic_slug, t]))
  for (const m of MISCONCEPTIONS) {
    const [r] = await conn.execute(
      'INSERT INTO misconceptions (slug, title, summary) VALUES (?, ?, ?)',
      [m.slug, m.title, m.summary]
    )
    const misId = r.insertId
    const t = topicBySlug[m.slug]
    if (t) {
      const furtherReading = MISCONCEPTION_FURTHER_READING[t.topic_slug] || []
      await conn.execute(
        'INSERT INTO misconception_topics (misconception_id, topic_slug, title, body_text, further_reading, sort_order) VALUES (?, ?, ?, ?, ?, ?)',
        [misId, t.topic_slug, t.title, t.body_text, furtherReading.length ? JSON.stringify(furtherReading) : null, t.sort_order]
      )
    }
  }
  console.log(`  ${MISCONCEPTIONS.length} misconceptions with topics.`)

  // Misconception entries (Israel, Jewish Race) + sources
  console.log('Inserting misconception_entries and misconception_entry_sources...')
  const allMisconceptionEntries = [
    ...ISRAEL_MISCONCEPTION_ENTRIES.map((e) => ({ ...e, topic_slug: 'israel' })),
    ...JEWISH_RACE_MISCONCEPTION_ENTRIES.map((e) => ({ ...e, topic_slug: 'jewish-race' })),
  ]
  for (const e of allMisconceptionEntries) {
    const [r] = await conn.execute(
      'INSERT INTO misconception_entries (topic_slug, slug, title, summary, body_text, sort_order) VALUES (?, ?, ?, ?, ?, ?)',
      [e.topic_slug, e.slug, e.title, e.summary || null, e.body_text || null, e.sort_order ?? 0]
    )
    const entryId = r.insertId
    let order = 0
    for (const s of e.sources || []) {
      await conn.execute(
        'INSERT INTO misconception_entry_sources (misconception_entry_id, label, url, sort_order) VALUES (?, ?, ?, ?)',
        [entryId, s.label, s.url || null, order++]
      )
    }
  }
  console.log(`  ${allMisconceptionEntries.length} misconception entries with sources.`)

  await conn.end()
  console.log('Seed done.')
}

run().catch((err) => {
  console.error(err)
  process.exit(1)
})
